{
  "call_summaries": [
    {
      "date": "2024-06-10T14:00:00-04:00",
      "participants": [
        {
          "name": "Violet Martinez",
          "email": "violet.martinez@northwindtraders.com",
          "role": "Lead Contact, Supply Chain Transformation"
        },
        {
          "name": "Marcus Patel",
          "email": "marcus.patel@adatum.com",
          "role": "Data Integration Lead, Adatum Corporation"
        },
