        {
          "topic": "Alert builder logic fix deployment schedule",
          "promised_by": "mario.rogers@adatum.com",
          "commitment_date": "2024-06-23T15:00:00-04:00",
          "description": "Mario Rogers committed that performance fixes for the custom alert builder will be tested in the dev environment and deployed to production by June 23, with documentation of performance benchmarks shared to Violet Martinez and relevant team leads.",
          "client_visible": true
        }
      ]
    }
  ],
  "recent_commitments": [
